function estaAutenticado(){return!!localStorage.getItem("token")}async function verificarSesion(){if(!localStorage.getItem("token"))return!1;try{return await API.me(),!0}catch{return localStorage.removeItem("token"),localStorage.removeItem("user"),!1}}function mostrarTopbar(){document.getElementById("topbar").style.display="flex";const e=localStorage.getItem("user");if(e)try{const t=JSON.parse(e);document.getElementById("username-display").textContent=`👤 ${t.username}`}catch{}}!async function(){document.getElementById("main-content");Router.register("/login",async e=>{Auth.renderLogin(e)}),Router.register("/register",async e=>{Auth.renderRegister(e)}),Router.register("/configuracion",async e=>{estaAutenticado()&&await verificarSesion()?(mostrarTopbar(),Pages.configuracion.render(e)):window.location.hash="#/login"}),Router.register("/",async e=>{estaAutenticado()&&await verificarSesion()?(mostrarTopbar(),Pages.clientes.render(e)):window.location.hash="#/login"}),Router.init()}();